SELECT SUM(number_of_transactions) AS total_transactions
FROM transaction_data
WHERE crypto_id = 'BTC' AND date = '2023-01-01';

SELECT AVG(average_transaction_volume_usd) AS avg_volume_usd
FROM transaction_volume
WHERE crypto_id = 'BTC';

SELECT SUM(unique_addresses) AS total_unique_addresses
FROM address_data
WHERE crypto_id = 'BTC' AND date = '0';

SELECT SUM(number_of_transactions) AS total_transactions
FROM transaction_data
WHERE date = '1' AND crypto_id = 'BTC';

SELECT unique_addresses 
FROM address_data 
WHERE date = (SELECT MIN(date) FROM address_data WHERE crypto_id = 'BTC') AND crypto_id = 'BTC';

SELECT DISTINCT crypto_id
FROM market_data
WHERE date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT AVG(average_block_time) AS avg_block_time
FROM blockchain_metrics
WHERE crypto_id = 'BTC' AND date = '1';

SELECT hash_rate
FROM blockchain_metrics
WHERE crypto_id = 'BTC' AND date = '1';
